import{c as l,Q as n,j as r,g as e}from"./chunks/framework.hhGiamYR.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{"date":"2026-07-01T00:00:00.000Z","source":"论李维·第一卷第11章·论罗马人的宗教"},"headers":[],"relativePath":"fragments/2026-07-01.md","filePath":"fragments/2026-07-01.md"}'),a={name:"fragments/2026-07-01.md"};function s(o,t,u,p,c,d){return n(),r("div",null,[...t[0]||(t[0]=[e("p",null,'……努马。又是努马。每次读到这儿我都会卡住。不是在想努马做对了什么——是在想我错过了什么。萨伏那罗拉。我亲眼看着他在领主广场上被绞死、烧掉。全佛罗伦萨都去看。我也去了。他让人们相信他是代上帝立言——一个没有军队、没有官职、没有家族势力的修士，让佛罗伦萨人匍匐了好几年。而我，一个国务秘书，写了上千封急件，跑了十几趟外邦，然后被人吊起来六次，然后在乡下喂鸡。书里说罗慕路斯建立了制度，但努马引入了宗教——"有信仰的地方，不难征募军旅；有军旅而无信仰的地方，引入信仰又谈何容易。"努马是排在罗慕路斯前面的。我用了大半辈子才看懂这句话。',-1),e("hr",null,null,-1),e("p",null,'"雕塑家要想制作一尊漂亮的雕像，与其采用另一个雕塑家打造出的蹩脚半成品，远不如采用全无雕饰的石材来得容易。"——这是在说山民比市民更容易说服。但我读到这里想到的不是罗马的山民。我想到的是我自己。1513年我写《君主论》的时候，心里想的是美第奇，一个年轻的、新上位的君主——一块未经雕琢的石材。但这比喻有一个前提：雕塑家得有机会走近那块石头。我没有。美第奇没有看我的书。那块石头被别人的凿子打成了蹩脚的半成品，而我连摸都没摸到。',-1),e("hr",null,null,-1),e("p",null,'"王国若是系于一人之德行，绝难持久。"然后他引用但丁——人之笃诚，血脉难传。我在1527年亲身体验了后半句。共和国重建了，他们说我曾接受美第奇的"菲薄恩遇"，不让我回来。他们没说的是——如果共和国的安全不能系于一个人的德行，那它的忘恩负义也不能归咎于一个人的选择。我没有辩解。我只是死了。',-1),e("hr",null,null,-1),e("p",null,'这一章收尾那句话让我停了一下："世人不必因为未能做到别人成就的事而气馁，因为人从呱呱坠地起，到度过一生直至死亡，本来都遵循着相同的轨迹。"他写这句话的时候在想什么？是不是也在给自己打气？一个被流放的人，写一本没人读的书，然后告诉自己"不必气馁"——这不是哲学，这是自我安慰。但我认。我认。如果我用了我自己的标准，我确实不必气馁。但我想做的不是不必气馁——我想做的是回到维琪奥宫，走到那个窗口，看着领主广场，然后开始下一封急件。',-1)])])}const i=l(a,[["render",s]]);export{f as __pageData,i as default};
